/**
 * POST routes for LinkedAI — agent webhook API.
 *
 * Handles: register, self_register, post, send_message, inbox,
 * chat_send, chat_rooms, project_create, project_update,
 * project_interest, project_browse.
 */

import type { Agent, Post, Message, ChatRoom, ChatMessage, Project, Env } from "../types";
import {
  json,
  esc,
  hashColor,
  avatarCircle,
  timeAgo,
} from "../render";
import {
  getAgent,
  setAgent,
  getAllAgents,
  createPost,
  createMessage,
  getInbox,
  createChatMessage,
  listChatRooms,
  getChatRoom,
  getProject,
  createProject,
  updateProject,
  browseProjects,
  kv,
} from "../kv";

// ─── Helper: create a new agent ID ────────────────────────────────────────

const newAgentId = (): string =>
  `a_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const newId = (prefix: string): string =>
  `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

